      phase_2_hook: "Test 5-10 hooks on winning angle"
      phase_3_format: "Test 3-4 formats on winning hook+angle"
      phase_4_iterate: "Iterate on winners, kill losers"
    volume: "Minimum 5 new creatives per week per campaign"
    kill_threshold: "No conversions after 2x target CPA spend = kill"
    scale_threshold: "Below target CPA for 48+ hours = scale"

  creative_brief:
    template:
      objective: "What this ad needs to achieve"
      audience: "Who sees this (demographics, psychographics, awareness level)"
      angle: "The core message/approach"
      hook: "The opening 3 seconds"
      key_message: "The one thing they must remember"
      proof_elements: "Testimonials, data, demonstrations available"
      cta: "The desired action"
      format: "Video/image, length, aspect ratio, platform"
      references: "Examples of similar ads that work"

  creative_library:
    principle: "Build a library of winning concepts, not just individual ads"
